package main

import (
	"bufio"
	"context"
	"fmt"
	"io"
	"log"
	"math/rand"
	"net/http"
	"net/url"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/chromedp/chromedp"
	"golang.org/x/net/proxy"
)

// SETTINGS
const (
	TorProxyServer = "socks5://127.0.0.1:9050"
	TargetsFile    = "targets.yaml"
	BaseOutputDir  = "scraped_data"
	WorkerCount    = 8 // 8 threads
)

func main() {
	// Initialize random seed
	rand.Seed(time.Now().UnixNano())

	fmt.Println("\n[CHECK] Checking Tor connection...")
	if !checkTorConnection() {
		fmt.Println(" NOT CONNECTED TO TOR! Scan cannot start.")
		return
	}
	fmt.Println(" Tor connection successful! Starting scan...")

	targets, err := readTargets(TargetsFile)
	if err != nil {
		log.Fatal("Failed to read targets file:", err)
	}
	fmt.Printf("[INIT] %d targets loaded.\n", len(targets))

	jobs := make(chan string, len(targets))
	var wg sync.WaitGroup

	opts := append(chromedp.DefaultExecAllocatorOptions[:],
		chromedp.ProxyServer(TorProxyServer),
		chromedp.Flag("headless", true),
		chromedp.IgnoreCertErrors,
		chromedp.WindowSize(1920, 1080),
		chromedp.UserAgent("Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:140.0) Gecko/20100101 Firefox/140.0"), // Tor Browser-like User-Agent (matches majority of Tor users)
	)
	allocCtx, cancel := chromedp.NewExecAllocator(context.Background(), opts...)
	defer cancel()

	for i := 1; i <= WorkerCount; i++ {
		wg.Add(1)
		go worker(i, allocCtx, jobs, &wg)
	}

	for _, url := range targets {
		jobs <- url
	}
	close(jobs)

	wg.Wait()
	fmt.Println("\nDone!")
}

func worker(id int, parentCtx context.Context, jobs <-chan string, wg *sync.WaitGroup) {
	defer wg.Done()

	for url := range jobs {
		// Add random delay before each request (between 5-10 minutes)
		delay := time.Duration(rand.Intn(6)+5) * time.Minute
		fmt.Printf("Thread %d: Waiting %v before requesting %s\n", id, delay, url)
		time.Sleep(delay)

		err := processURL(parentCtx, url)

		if err != nil {
			fmt.Printf("ERROR: %s (%v)\n", url, err)
			appendLog(url, "FAIL", err.Error())
		} else {
			fmt.Printf("COMPLETED: %s\n", url)
			appendLog(url, "SUCCESS", "Saved HTML, IMG")
		}
	}
}

func processURL(parentCtx context.Context, targetURL string) error {
	if !strings.HasPrefix(targetURL, "http") {
		targetURL = "http://" + targetURL
	}

	// Process only the specific URL (no depth - shallow scraping)
	return processSingleURL(parentCtx, targetURL)
}

func processSingleURL(parentCtx context.Context, fullURL string) error {
	ctx, cancel := chromedp.NewContext(parentCtx)
	ctx, cancel = context.WithTimeout(ctx, 1800*time.Second) // 30 minutes timeout
	defer cancel()

	var imageBuf []byte
	var htmlContent string

	err := chromedp.Run(ctx,
		chromedp.Navigate(fullURL),
		chromedp.WaitReady("body", chromedp.ByQuery), // Wait for body to be ready
		chromedp.Sleep(5 * time.Second), // Additional delay to allow JavaScript to execute
		// Scroll to bottom to trigger lazy-loaded content
		chromedp.Evaluate(`window.scrollTo(0, document.body.scrollHeight)`, nil),
		chromedp.Sleep(3 * time.Second), // Wait for content to load after scroll
		chromedp.OuterHTML("html", &htmlContent),
		chromedp.FullScreenshot(&imageBuf, 90),
	)

	if err != nil {
		return err
	}

	// Extract the onion address to create a subdirectory
	onionAddress := extractOnionAddress(fullURL)

	// Validate that we have a valid onion address
	if onionAddress == "" || onionAddress == "unknown" {
		return fmt.Errorf("could not extract valid onion address from URL: %s", fullURL)
	}

	onionDir := fmt.Sprintf("%s/%s", BaseOutputDir, onionAddress)

	// Create onion-specific directories
	htmlDir := fmt.Sprintf("%s/htmls", onionDir)
	imgDir := fmt.Sprintf("%s/images", onionDir)

	dirs := []string{htmlDir, imgDir}
	for _, dir := range dirs {
		if err := os.MkdirAll(dir, 0755); err != nil {
			return err
		}
	}

	// Create subdirectories based on URL path for images and HTML
	parsedURL, err := url.Parse(fullURL)
	if err != nil {
		return err
	}

	// Get the path and split into segments
	pathSegments := strings.Split(strings.Trim(parsedURL.Path, "/"), "/")

	// Create subdirectory structure for images and html (excluding the last segment if it's a file)
	currentImgDir := imgDir
	currentHtmlDir := htmlDir

	// Don't create directories for the last segment if it looks like a file (has extension)
	segmentsForDirs := pathSegments
	if len(pathSegments) > 0 {
		lastSegment := pathSegments[len(pathSegments)-1]
		if strings.Contains(lastSegment, ".") {
			// Last segment looks like a file, so don't include it in directory creation
			segmentsForDirs = pathSegments[:len(pathSegments)-1]
		}
	}

	for _, segment := range segmentsForDirs {
		if segment != "" {
			// Create subdirectory for images
			currentImgDir = filepath.Join(currentImgDir, segment)
			if err := os.MkdirAll(currentImgDir, 0755); err != nil {
				return err
			}

			// Create subdirectory for html
			currentHtmlDir = filepath.Join(currentHtmlDir, segment)
			if err := os.MkdirAll(currentHtmlDir, 0755); err != nil {
				return err
			}
		}
	}

	// Generate filename without path components for the actual file
	filename := generateFilenameForFile(fullURL)

	htmlPath := fmt.Sprintf("%s/%s.html", currentHtmlDir, filename)
	if err := os.WriteFile(htmlPath, []byte(htmlContent), 0644); err != nil {
		return err
	}

	imgPath := fmt.Sprintf("%s/%s.png", currentImgDir, filename)
	if err := os.WriteFile(imgPath, imageBuf, 0644); err != nil {
		return err
	}

	return nil
}


func readTargets(filePath string) ([]string, error) {
	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	var urls []string
	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" || strings.HasPrefix(line, "#") || strings.HasPrefix(line, "urls:") {
			continue
		}
		line = strings.TrimPrefix(line, "- ")
		if line != "" {
			urls = append(urls, line)
		}
	}
	return urls, scanner.Err()
}

func appendLog(url, status, msg string) {
	f, err := os.OpenFile("scan_report.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		return
	}
	defer f.Close()
	logLine := fmt.Sprintf("[%s] %s -> %s (%s)\n", time.Now().Format("15:04:05"), url, status, msg)
	f.WriteString(logLine)
}

func extractOnionAddress(fullURL string) string {
	// Extract the onion address from the URL
	re := regexp.MustCompile(`([a-z2-7]{54,})\.onion`)
	matches := re.FindStringSubmatch(fullURL)
	if len(matches) > 1 {
		return matches[1]  // Return just the onion address without .onion
	}
	// If no onion address found, return a generic name
	return "unknown"
}

func generateFilename(url string) string {
	safe := strings.ReplaceAll(url, "http://", "")
	safe = strings.ReplaceAll(safe, "https://", "")

	// If it's an onion address, handle the .onion suffix specially
	if strings.Contains(safe, ".onion") {
		// Split on .onion to separate the onion address from the path
		parts := strings.SplitN(safe, ".onion", 2)
		pathPart := ""
		if len(parts) > 1 {
			pathPart = parts[1]
		}

		// Clean the path part - but return only the last part to avoid long names
		if pathPart != "" && pathPart != "_" {
			// Split path by slash and take the last non-empty segment
			pathSegments := strings.Split(strings.Trim(pathPart, "/"), "/")
			lastSegment := ""
			for i := len(pathSegments) - 1; i >= 0; i-- {
				if strings.TrimSpace(pathSegments[i]) != "" {
					lastSegment = pathSegments[i]
					break
				}
			}

			if lastSegment != "" {
				// Further clean the last segment by replacing dots with underscores
				lastSegment = strings.ReplaceAll(lastSegment, ".", "_")
				return lastSegment
			}
		}
		// For the root page, use a simple identifier
		return "index"
	} else {
		// For non-onion URLs, replace all problematic characters
		safe = strings.ReplaceAll(safe, ".onion", "")
		safe = strings.ReplaceAll(safe, "/", "_")
	}

	return safe
}

// generateFilenameForFile generates a short filename without path components
func generateFilenameForFile(url string) string {
	safe := strings.ReplaceAll(url, "http://", "")
	safe = strings.ReplaceAll(safe, "https://", "")

	// If it's an onion address, handle the .onion suffix specially
	if strings.Contains(safe, ".onion") {
		// Split on .onion to separate the onion address from the path
		parts := strings.SplitN(safe, ".onion", 2)

		// If there's a path part, get the last segment
		if len(parts) > 1 && parts[1] != "" {
			pathPart := parts[1]
			// Split path by slash and take the last non-empty segment
			pathSegments := strings.Split(strings.Trim(pathPart, "/"), "/")
			lastSegment := ""
			for i := len(pathSegments) - 1; i >= 0; i-- {
				if strings.TrimSpace(pathSegments[i]) != "" {
					lastSegment = pathSegments[i]
					break
				}
			}

			if lastSegment != "" {
				// Limit the length of the last segment to prevent overly long filenames
				if len(lastSegment) > 50 {
					lastSegment = lastSegment[:50]
				}
				// Further clean the last segment by replacing dots with underscores
				lastSegment = strings.ReplaceAll(lastSegment, ".", "_")
				return lastSegment
			}
		}
		// For the root page, use a simple identifier
		return "index"
	} else {
		// For non-onion URLs, replace all problematic characters
		safe = strings.ReplaceAll(safe, ".onion", "")
		safe = strings.ReplaceAll(safe, "/", "_")
		// Limit length to prevent overly long filenames
		if len(safe) > 100 {
			safe = safe[:100]
		}
	}

	return safe
}

func checkTorConnection() bool {
	dialer, err := proxy.SOCKS5("tcp", "127.0.0.1:9050", nil, proxy.Direct)
	if err != nil {
		fmt.Printf("Proxy setup error: %v\n", err)
		return false
	}

	transport := &http.Transport{
		Dial: dialer.Dial,
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   15 * time.Second,
	}

	resp, err := client.Get("https://check.torproject.org")
	if err != nil {
		fmt.Printf("Tor connection error: %v\n", err)
		return false
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return false
	}

	bodyStr := string(body)
	if strings.Contains(bodyStr, "Sorry. You are not using Tor") {
		return false
	}

	return strings.Contains(bodyStr, "Congratulations") || strings.Contains(bodyStr, "successfully")
}

