```
And you must install the browsers:
```bash
go run github.com/playwright-community/playwright-go/cmd/playwright install --with-deps firefox
```

Here is how you would refactor your script to use the **Firefox engine** with stealth-optimized settings:

```go
package main

import (
	"bufio"
	"fmt"
	"io"
	"log"
	"math/rand"
	"net/http"
	"net/url"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/playwright-community/playwright-go"
	"golang.org/x/net/proxy"
)

const (
	TorProxyServer = "socks5://127.0.0.1:9050"
	TargetsFile    = "targets.yaml"
	BaseOutputDir  = "scraped_data"
	WorkerCount    = 8
	// Official Tor Browser (Firefox ESR) UA
	TorUA = "Mozilla/5.0 (Windows NT 10.0; rv:128.0) Gecko/20100101 Firefox/128.0"
)

func main() {
	rand.Seed(time.Now().UnixNano())

	fmt.Println("[CHECK] Verifying Tor connection...")
	if !checkTorConnection() {
		fmt.Println("NOT CONNECTED TO TOR! Aborting.")
		return
	}

	// Start Playwright
	pw, err := playwright.Run()
	if err != nil {
		log.Fatalf("could not start playwright: %v", err)
	}
	defer pw.Stop()

	// Launch Firefox with Tor Proxy
	browser, err := pw.Firefox.Launch(playwright.BrowserTypeLaunchOptions{
		Headless: playwright.Bool(true),
		Proxy: &playwright.Proxy{
			Server: playwright.String(TorProxyServer),
		},
	})
	if err != nil {
		log.Fatalf("could not launch firefox: %v", err)
	}
	defer browser.Close()

	targets, _ := readTargets(TargetsFile)
	jobs := make(chan string, len(targets))
	var wg sync.WaitGroup

	for i := 1; i <= WorkerCount; i++ {
		wg.Add(1)
		go worker(i, browser, jobs, &wg)
	}

	for _, url := range targets {
		jobs <- url
	}
	close(jobs)
	wg.Wait()
}

func worker(id int, browser playwright.Browser, jobs <-chan string, wg *sync.WaitGroup) {
	defer wg.Done()

	for targetURL := range jobs {
		// Random delay 5-10 mins
		delay := time.Duration(rand.Intn(6)+5) * time.Minute
		fmt.Printf("Thread %d: Waiting %v for %s\n", id, delay, targetURL)
		time.Sleep(delay)

		err := processURL(browser, targetURL)
		if err != nil {
			fmt.Printf("ERROR [%s]: %v\n", targetURL, err)
			appendLog(targetURL, "FAIL", err.Error())
		} else {
			fmt.Printf("SUCCESS: %s\n", targetURL)
			appendLog(targetURL, "SUCCESS", "Saved")
		}
	}
}

func processURL(browser playwright.Browser, fullURL string) error {
	// Create a context specifically designed to mimic Tor Browser
	context, err := browser.NewContext(playwright.BrowserNewContextOptions{
		UserAgent: playwright.String(TorUA),
		Viewport: &playwright.Size{
			Width:  1000,
			Height: 800,
		},
		IgnoreHTTPSErrors: playwright.Bool(true),
		ExtraHTTPHeaders: map[string]string{
			"Accept":           "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
			"Accept-Language":  "en-US,en;q=0.5",
			"Sec-Fetch-Dest":   "document",
			"Sec-Fetch-Mode":   "navigate",
			"Sec-Fetch-Site":   "none",
			"Sec-Fetch-User":   "?1",
		},
	})
	if err != nil {
		return err
	}
	defer context.Close()

	page, err := context.NewPage()
	if err != nil {
		return err
	}

	// Set a long timeout for slow .onion sites (30 mins)
	page.SetDefaultTimeout(1800000)

	if _, err := page.Goto(fullURL); err != nil {
		return err
	}

	// Wait for body and simulate human-like scroll to trigger lazy loading
	time.Sleep(5 * time.Second)
	_, _ = page.Evaluate(`window.scrollTo(0, document.body.scrollHeight)`)
	time.Sleep(3 * time.Second)

	// Capture HTML and Screenshot
	htmlContent, _ := page.Content()
	screenshot, _ := page.Screenshot(playwright.PageScreenshotOptions{
		FullPage: playwright.Bool(true),
	})

	return saveData(fullURL, htmlContent, screenshot)
}

// ... Keep your existing helper functions: 
// readTargets, appendLog, extractOnionAddress, checkTorConnection, saveData (refactored for bytes)
