### 2. Scraping Titles for the Links
To get the titles (the text inside the `<a>` tag) and the URLs together, we need to modify the JavaScript evaluation inside `processURL`. We will have the browser return an array of objects, then filter them by the Onion regex in Go.

#### Updated `processURL` function:

```go
func processURL(browser playwright.Browser, fullURL string) (map[string]string, error) {
    // ... (context and page setup remains same as before) ...

    if _, err := page.Goto(fullURL); err != nil {
        return nil, err
    }

    // Wait and scroll logic
    time.Sleep(5 * time.Second)
    _, _ = page.Evaluate(`window.scrollTo(0, document.body.scrollHeight)`)
    time.Sleep(2 * time.Second)

    // REVISED: Extract both the URL (href) and the text (innerText)
    rawLinks, err := page.Evaluate(`() => {
        return Array.from(document.querySelectorAll('a')).map(a => ({
            href: a.href,
            text: a.innerText.trim()
        }));
    }`)
    if err != nil {
        return nil, err
    }

    onionRegex := regexp.MustCompile(`https?://[a-z2-7]{56}\.onion[^\s"']*`)

    // Use a map to store URL -> Title (automatically deduplicates URLs)
    discovered := make(map[string]string)

    if linkObjects, ok := rawLinks.([]interface{}); ok {
        for _, obj := range linkObjects {
            entry := obj.(map[string]interface{})
            linkStr := fmt.Sprintf("%v", entry["href"])
            titleStr := fmt.Sprintf("%v", entry["text"])

            if onionRegex.MatchString(linkStr) {
                // If title is empty (just an image link, etc), give it a placeholder
                if titleStr == "" {
                    titleStr = "[No Text]"
                }
                // Cleanup newlines in titles to keep the text file clean
                titleStr = strings.ReplaceAll(titleStr, "\n", " ")
                discovered[linkStr] = titleStr
            }
        }
    }

    return discovered, nil
}
