// getInterSiteDelay returns a Gaussian-distributed delay for inter-site waits.
// Default: 8-15 minutes (mean=11.5, stdDev=1.75)
// Custom: optInterSiteDelay ± 50%
func getInterSiteDelay() time.Duration {
	var mean, stdDev float64

	if optInterSiteDelay == 0 {
		// Stealth default: Gaussian 8-15 min
		mean = 11.5  // (8+15)/2
		stdDev = 1.75 // (15-8)/4
	} else {
		// Custom: mean ± 50%
		mean = float64(optInterSiteDelay)
		stdDev = mean / 4.0
	}

	// Generate normal distribution value
	minutes := (rand.NormFloat64() * stdDev) + mean

	// Clamp to minimum (mean - 2*stdDev to avoid negative/very low values)
	minMinutes := mean - 2*stdDev
	if minutes < minMinutes {
		minutes = minMinutes
	}
	if minutes < 1 {
		minutes = 1
	}

	delay := time.Duration(minutes * 60) * time.Second
	fmt.Printf("[STEALTH] Inter-site delay: %v\n", delay)
	return delay
}

